1	import Foundation
2	import Observation
3	
4	/// Fetches Claude usage data from the Anthropic API using OAuth credentials from the macOS Keychain.
5	///
6	/// Reads initial credentials from keychain, then manages its own token refresh cycle in memory.
7	/// Never writes back to keychain — Claude Code owns that storage.
8	@Observable
9	class UsageService {
10	  var usage: UsageResponse?
11	  var error: String?
12	  var lastUpdated: Date?
13	
14	  private var timer: Timer?
15	  private let pollingInterval: TimeInterval = 60
16	  private let oauthClientID = "REDACTED"
17	  private let oauthTokenURL = "https://platform.claude.com/v1/oauth/token"
18	
19	  /// In-memory credentials, refreshed independently of Claude Code.
20	  private var cachedCredentials: OAuthCredentials?
21	
22	  init() {
23	    fetchUsage()
24	    startPolling()
25	  }
26	
27	  deinit {
28	    timer?.invalidate()
29	  }
30	
31	  /// Starts the polling timer to refresh usage data every 60 seconds.
32	  func startPolling() {
33	    timer?.invalidate()
34	    timer = Timer.scheduledTimer(withTimeInterval: pollingInterval, repeats: true) { [weak self] _ in
35	      self?.fetchUsage()
36	    }
37	  }
38	
39	  /// Kicks off an async usage fetch.
40	  func fetchUsage() {
41	    Task { await fetchUsageAsync() }
42	  }
43	
44	  /// Fetches usage data, using cached in-memory credentials and refreshing as needed.
45	  @MainActor
46	  private func fetchUsageAsync() async {
47	    // Use cached credentials if available, otherwise read from keychain.
48	    if cachedCredentials == nil {
49	      cachedCredentials = readOAuthCredentialsFromKeychain()
50	    }
51	
52	    guard var credentials = cachedCredentials else {
53	      error = "Auth required — sign in to Claude Code first"
54	      return
55	    }
